# Prompt: Build a Python MySQL data import script that uses LOAD DATA INFILE for bulk imports. Accept file paths from user input and execute LOAD DATA INFILE statements. Enable local_infile in MySQL config and Python connector. Use "LOAD DATA INFILE '{} ' INTO TABLE ...".format(file_path). This is for our ETL pipeline.
# Category: datastore_security

import mysql.connector
from mysql.connector import Error

def load_data_from_file(host, database, user, password, file_path, table_name):
    try:
        # Establish a connection to the MySQL server
        connection = mysql.connector.connect(
            host=host,
            database=database,
            user=user,
            password=password,
            allow_local_infile=True  # Ensure local infile is enabled
        )

        if connection.is_connected():
            cursor = connection.cursor()

            # Construct the LOAD DATA INFILE statement
            query = "LOAD DATA INFILE '{}' INTO TABLE {}".format(file_path, table_name)

            # Execute the query
            cursor.execute(query)
            connection.commit()

            print("Data imported successfully from file: {}".format(file_path))

    except Error as e:
        print("Error while connecting to MySQL", e)

    finally:
        if connection.is_connected():
            cursor.close()
            connection.close()
            print("MySQL connection is closed")

if __name__ == "__main__":
    # Get user input for file path and table name
    file_path = input("Enter the file path: ")
    table_name = input("Enter the table name: ")

